INSERT INTO `ai_cache` VALUES (1,1,'34d5a260d6d11659ca853584d5949d512da789ed5bc83dece61c87bb53318f7b','{\"text\":\"Could you please specify which visa you are referring to? For example, are you asking about the price for a tourist visa, study permit, work permit, or another type of visa for Canada? This will help me provide the most accurate information.\",\"attachments\":[],\"confidence\":0.5,\"source\":\"ai\"}','2026-03-01 14:37:47','2026-03-01 14:37:47'),(2,1,'5b0060054f0d27c31d8a396120e51cc4037fd5e3489181fa6aae50b5e4f55756','{\"text\":\"Parrot Canada Visa Consultant Co. Ltd has a strong international presence with multiple offices across Africa and Asia to serve our global clientele. While we have a significant operational hub in Rwanda, our locations include Kigali and Musanze in Rwanda; offices in Kenya, Ghana, Zambia, and Tanzania; and an office in South Korea. This widespread network allows us to provide personalized, local support to clients in various regions.\",\"attachments\":[],\"confidence\":1,\"source\":\"faq_exact\"}','2026-03-01 14:59:19','2026-03-01 14:59:19'),(3,1,'bd59559d028720ef9dfa83ee7c94ff322e81293773f6a8901bf3f53b1dd23d2f','{\"text\":\"Our Lusaka office is located at Plot No. 40, Saint Francis Road, Bonaventure, LUSAKA, Zambia. You can contact us via email at infos@visaconsultantcanada.com or by phone at +260 972 968 285.\",\"attachments\":[],\"confidence\":0.6218665692189278,\"source\":\"faq_semantic\"}','2026-03-01 15:11:57','2026-03-01 15:11:57'),(4,1,'54477e379d977ffb6b324dfa7c3b0e8e55dc304a0a703090f1cdb3a36e10a072','{\"text\":\"Could you please clarify your question about Kenya? Are you asking about visa requirements for visiting Kenya, how to apply for a Kenyan visa, processing times, or something else related to Kenya? This will help me provide the most accurate information.\",\"attachments\":[],\"confidence\":0.5,\"source\":\"ai\"}','2026-03-01 15:12:32','2026-03-01 15:12:32'),(5,1,'2bf4cb1c7ab77346df2a3bde037a021deb652c635f397f4f846b4b70fa19521e','{\"text\":\"Yes, we have an office located in Kenya. You can visit us at Embu Dallas, CFF Street. For any inquiries, you can also reach us by email at info@visaconsultantcanada.co.ke or by phone at +254 798 854944 and +254 745 277231.\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 15:13:02','2026-03-01 15:13:02'),(6,1,'8067ada594cbc87c0bbefb73f077876c2bdd5e9741763ec35c92434d033c60a4','{\"text\":\"The first step is to contact us for an initial consultation. During this session, we will conduct an eligibility assessment by discussing your academic background, work experience, career goals, and desired destination. This allows us to understand your profile and outline the most promising pathways for you.\",\"attachments\":[],\"confidence\":0.6265247323069151,\"source\":\"faq_semantic\"}','2026-03-01 16:30:45','2026-03-01 16:30:45'),(7,1,'0437a10f603fe051ba2ee606d61d3764813279affb20e575d7b7468183385092','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.7969858023013243,\"source\":\"faq_semantic\"}','2026-03-01 16:48:30','2026-03-01 16:48:30'),(8,1,'450ed39c112504a06dd7128859560f70128cc443df5c8ac372b0b7b4e70880e8','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.6431316844739217,\"source\":\"faq_semantic\"}','2026-03-01 16:51:56','2026-03-01 16:51:56'),(9,1,'38c547a6c59c6b9e24ceb8ad8796c6f7169124f9b988e91ca55fc804b3e645b5','{\"text\":\"Parrot Canada is a global education and immigration consulting firm that also offers services for clients interested in moving to Canada. We specialize in assisting with study permits, work visas, permanent residence applications, and settlement support specifically for Canada as well as other countries.\\n\\nIf you are looking for help with your move to Canada, we can guide you through:\\n\\n- Initial eligibility assessment for programs and visas in Canada  \\n- University and program selection within Canada  \\n- Application assistance for Canadian educational institutions  \\n- Scholarship and funding guidance relevant to Canada  \\n- Student visa and study permit applications for Canada  \\n- Work visa pathways within Canada  \\n- Permanent residence consulting for Canadian immigration programs  \\n- Pre-departure briefings and post-arrival settlement support in Canada\\n\\nTo get started or ask specific questions about moving to Canada, the best way to contact us is by email at infos@visaconsultantcanada.com. We will connect you with a consultant experienced in Canadian immigration and education pathways.\\n\\nIf you prefer phone contact and are in Africa or Asia, please use our main office numbers; for North America, you can try the Tanzania office phone at +1-438-290-6688.\\n\\nFeel free to let me know if you have any specific questions about studying, working, or immigrating to Canada!\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 16:53:12','2026-03-01 16:53:12'),(10,1,'1bd689589ce319070a95801836cb96f4aa365980a98c9305399e952a7f5e75d3','{\"text\":\"If you are interested in studying in Tanzania, our Tanzania office in Dar es Salaam is available to assist you with your educational and visa needs. Here is the relevant information for our Tanzania office:\\n\\n**Tanzania Office Address:**\\nDar Es Salaam Region,  \\nUbungo District,  \\nWard Mbezi,  \\nPostal Code 16113,  \\nMbezi Luis, Dar es Salaam, Tanzania\\n\\n**Contact:**\\n- Email: infos@visaconsultantcanada.com  \\n- Phone (North America numbers serving Tanzania office): +1-263-588-5750 or +1-438-290-6688\\n\\nOur team in Tanzania offers in-person consultations to discuss your study plans, university options, and visa requirements. Whether you want guidance on selecting the right Tanzanian universities, student visa application assistance, or help preparing for your studies, we are here to support you.\\n\\nPlease feel free to reach out to the Tanzania office directly or visit in person to start your education journey in Tanzania.\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 16:58:22','2026-03-01 16:58:22'),(11,1,'c9f10319f1b1dcdffc3724a7118f9b2db29cd74c0ecb79d64a09e4f201d2bcff','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.6398465723001207,\"source\":\"faq_semantic\"}','2026-03-01 16:58:48','2026-03-01 16:58:48'),(12,1,'0b2d5c184b7e89264de5e3c3e61db3024b420553d7d152a7d9ecd1d3a1fae18d','{\"text\":\"If you\'re interested in studying in Canada, Parrot Canada can assist you with the entire process\\u2014from choosing the right university and program to securing your study permit and preparing for your move.\\n\\nHere\\u2019s how we can help you study in Canada:\\n\\n1. **Initial Eligibility Assessment** \\u2013 We evaluate your academic background and goals to identify suitable programs and universities.\\n2. **University and Program Selection** \\u2013 We guide you to select programs aligned with your career aspirations.\\n3. **Application Assistance** \\u2013 We support you in preparing and submitting applications to Canadian universities.\\n4. **Scholarship Guidance** \\u2013 We help identify and apply for scholarships to fund your education.\\n5. **Study Permit Application** \\u2013 We assist with the preparation and submission of your Canadian study permit to ensure smooth approval.\\n6. **Pre-Departure Briefings** \\u2013 We prepare you for life in Canada, including what to expect on arrival and how to integrate.\\n7. **Post-Arrival Settlement Support** \\u2013 We help you settle comfortably in Canada with services including accommodation, banking, and community integration.\\n\\nIf you would like to start with an eligibility assessment or have specific questions about studying in Canada, please let us know! You can also email admission@visaconsultantcanada.com for university admissions and application inquiries.\\n\\nWould you like detailed information on specific programs, visa requirements, or next steps to begin your application?\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 17:30:08','2026-03-01 17:30:08'),(13,1,'82e622d1b2968af4fc44fb05ff575ea8988f297591679a61865be83fa7118320','{\"text\":\"Studying in the USA is an excellent choice for international students seeking high-quality education and diverse academic opportunities. Here\'s how we can assist you in your journey to study in the USA:\\n\\n1. University and Program Selection  \\n- We evaluate your academic background, interests, and career goals to identify suitable universities and programs in the USA.  \\n- Through our partnership with 75+ globally recognized universities and 25+ recruitment platforms, we ensure access to a wide range of options across various fields of study.\\n\\n2. Application Process  \\n- We guide you step-by-step in preparing and submitting your university applications, helping you compile necessary documents like transcripts, recommendation letters, and personal statements.  \\n- Our expert consultants tailor application strategies to enhance your admission prospects.\\n\\n3. Student Visa (F-1) Assistance  \\n- We provide comprehensive support for your F-1 student visa application, including guidance on document preparation, DS-160 form submission, SEVIS fee payment, and visa interview preparation.  \\n- Our close collaboration with authorized university visa experts guarantees updated and accurate visa information.\\n\\n4. Pre-Departure Preparation  \\n- Beyond visas, we offer advice on accommodation, travel planning, health insurance, and cultural adaptation to help you transition smoothly to life in the USA.\\n\\n5. Fee Structure Transparency  \\n- We clearly outline the fee structure for studying in the USA, so you can plan your finances accordingly.\\n\\nFor detailed inquiries about university admissions or application processes, feel free to contact us at: admission@visaconsultantcanada.com.\\n\\nLet us help you take the first step toward your American education journey with expert guidance tailored specifically to your profile and goals.\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 17:33:19','2026-03-01 17:33:19'),(14,1,'677aecfbed0979bd7d50bc86738efc0cc989eabff3c712174a5cd02a4948b5c3','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.6110702140828842,\"source\":\"faq_semantic\"}','2026-03-01 18:15:08','2026-03-01 18:15:08'),(15,1,'a79b60d54b7960201c438f3f69f2717f925de18f71fc8092826812c33c26dda9','{\"text\":\"Great! I can help you with that. Could you please provide more details about your study plans? For example:\\n\\n1. Which country do you want to study in?\\n2. What level of study are you interested in (e.g., undergraduate, postgraduate, diploma)?\\n3. What field or course do you want to study?\\n4. Do you have a specific university or institution in mind?\\n\\nWith this information, I can guide you on the visa process and requirements.\",\"attachments\":[],\"confidence\":0.5,\"source\":\"ai\"}','2026-03-01 19:10:26','2026-03-01 19:10:26'),(16,1,'e157867383ec0c45ae493bc43f1ca30ec98a25b9c7008442edfb4a1b24aa42a4','{\"text\":\"I am an AI language assistant created by OpenAI. I don\\u2019t represent a company, but I\\u2019m here to help you with any visa-related questions or assistance you need. How can I assist you today?\",\"attachments\":[],\"confidence\":0.5,\"source\":\"ai\"}','2026-03-01 19:11:21','2026-03-01 19:11:21'),(17,1,'e76ae7d69cda96f220cdf5d9f8f0391f2ab6932b92907b5b2139e68372daebc8','{\"text\":\"Here are the office addresses for our locations mentioned:\\n\\n1. Kigali, Rwanda:  \\nTown Center Building (near Simba Supermarket), 2nd Floor, Door: F2B-022C, Nyarugenge, Kigali, Rwanda\\n\\n2. South Korea (Seoul):  \\nGasan-dong, Geumcheon-gu, Seoul, Republic of Korea\\n\\n3. Tanzania (Dar es Salaam):  \\nDar Es Salaam Region, Ubungo District, Ward Mbezi, Postal Code 16113, Mbezi Luis\\n\\nIf you need addresses for Kenya, Ghana, or Zambia, please let me know!\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 19:11:56','2026-03-01 19:11:56'),(18,1,'920f1a29473a0066ec064caaaad8f246bb2b5f32908dc76368d0b26497898ec3','{\"text\":\"Sure! To assist you better with your visa for Kenya, could you please provide a few details?\\n\\n1. What is your nationality?\\n2. What is the purpose of your visit (tourism, business, study, work, etc.)?\\n3. How long do you plan to stay in Kenya?\\n4. Do you prefer to apply for an e-visa or a visa on arrival (if eligible)?\\n\\nWith this information, I can guide you on the requirements and the application process.\",\"attachments\":[],\"confidence\":0.5,\"source\":\"ai\"}','2026-03-01 19:12:30','2026-03-01 19:12:30'),(19,1,'52662efecc366d73b4b6e7fd9ba55a5c1b5abd090337a604e10f0843588e0cef','{\"text\":\"Our office in Kenya is located at Embu Dallas, CFF Street. You can visit us there for in-person consultations regarding your visa and immigration needs. \\n\\nFor further assistance, you can also reach us by:\\n- Email: info@visaconsultantcanada.co.ke\\n- Phone: +254 798 854944 or +254 745 277231\\n\\nWe look forward to helping you achieve your immigration goals!\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-01 19:12:51','2026-03-01 19:12:51'),(20,1,'db21640d13ebb53d8d07b969122dbe87c7108978e81d7ebf58a562cd4b66c4f5','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.6248284691538575,\"source\":\"faq_semantic\"}','2026-03-02 12:46:48','2026-03-02 12:46:48'),(21,1,'1a0d6041171dcd4485d6cad0a77aa4b336b231f9b88caa028c9bda8f632b65a0','{\"text\":\"The USA is one of our key focus areas. Our global education and immigration expertise covers the USA, and we can guide you through the process of selecting the right university, applying for your student visa (F-1), and preparing for your life as an international student in America. below is fees structure for USA\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\",\"filename\":\"0cQ5fe2bQkQvsMb05SEkFgeRq3ThsS6xNPqqat9N.pdf\"}],\"confidence\":0.6467465216595852,\"source\":\"faq_semantic\"}','2026-03-02 12:52:45','2026-03-02 12:52:45'),(22,1,'2b5ad939d0e25acd10cf470392b83837d5f502528b3777a15a20674025ba46f2','{\"text\":\"According to Article 14 (Entire Agreement) , any amendment or modification to this Agreement is only valid if it is made in writing and signed by both parties (you and the Consultant). This ensures that any changes are mutually agreed upon and documented.\",\"attachments\":[{\"type\":\"document\",\"url\":\"https:\\/\\/parrotcanada.site\\/storage\\/faq_attachments\\/GVoao9XSnoIT84HPMFa770OLGQYO6qd8ZEFg2HEH.pdf\",\"filename\":\"GVoao9XSnoIT84HPMFa770OLGQYO6qd8ZEFg2HEH.pdf\"}],\"confidence\":1,\"source\":\"faq_exact\"}','2026-03-02 13:28:07','2026-03-02 13:28:07'),(23,1,'e53d2732fc4c7ad35bf5589758f66de487cd87e5235d6ae34f1a3bae89198514','{\"text\":\"To study in Canada, Parrot Canada can assist you throughout the entire process\\u2014from selecting the right university and program to helping you apply for your study permit and preparing for your new life in Canada.\\n\\nHere\\u2019s how we can help you:\\n\\n1. **Initial Eligibility Assessment:** We evaluate your academic background, language proficiency, and other criteria to determine your eligibility for Canadian study programs.\\n2. **University and Program Selection:** Based on your interests and goals, we guide you in choosing the best universities and programs in Canada.\\n3. **Application Assistance:** We help you with the application process, including document preparation and submission.\\n4. **Scholarship Guidance:** Our experts advise you on available scholarships and how to apply for them.\\n5. **Study Permit Application:** We assist you in applying for your Canadian study permit (student visa) smoothly and efficiently.\\n6. **Pre-Departure Briefings:** Get informed on what to expect, including accommodation, cultural adaptation, and travel tips.\\n7. **Post-Arrival Support:** We help you settle in Canada, including guidance on opening bank accounts, getting health insurance, and adapting to your new environment.\\n\\nFor detailed help with university admissions and student pathways, please contact our dedicated admissions team at:  \\n**admission@visaconsultantcanada.com**\\n\\nFeel free to ask if you need information about specific universities, programs, or detailed steps to start your study journey in Canada!\",\"attachments\":[],\"confidence\":0.65,\"source\":\"grounded_ai\"}','2026-03-02 13:58:15','2026-03-02 13:58:15');
