INSERT INTO `knowledge_base` VALUES (5,1,'Where is Parrot Canada\'s head office or main location?','Parrot Canada Visa Consultant Co. Ltd has a strong international presence with multiple offices across Africa and Asia to serve our global clientele. While we have a significant operational hub in Rwanda, our locations include Kigali and Musanze in Rwanda; offices in Kenya, Ghana, Zambia, and Tanzania; and an office in South Korea. This widespread network allows us to provide personalized, local support to clients in various regions.','[0.042664114,0.017723998,0.08406306,0.036197722,-0.05023166,0.00054618734,-0.0007694945,0.045686446,0.0005333746,-0.011544614,-0.021460915,-0.014104227,0.0043694987,-0.03291767,-0.07178629,0.021624919,0.0454053,0.0381189,-0.025396978,0.049903657,0.04043836,0.03493256,-0.046811037,0.0382829,0.011691045,0.04383556,-0.037134882,0.019809175,0.0186963,-0.024225531,0.017349135,-0.021015765,-0.050981387,0.031535365,-0.026685571,-0.0073156888,0.04336698,-0.03408912,-0.022327786,-0.008492993,0.04343727,0.00729226,0.016739983,0.03291767,0.014115941,0.027083863,-0.016259689,-0.012159623,-0.031113641,0.007104828,-0.01623626,0.04296869,-0.035283994,0.019352311,-0.03736917,-0.026966719,0.026966719,-0.024155244,0.00044588215,0.011790617,0.03134793,-0.02959076,0.03734574,0.017419422,0.01623626,0.02602956,-0.03167594,0.0017147061,-0.039782353,0.015053099,-0.01345993,0.09952617,0.010800744,-0.023300089,-0.041984674,0.0069876835,-0.046108168,0.06494504,0.027247865,-0.030223342,-0.03071535,-0.004275783,0.018368294,0.016130831,-0.03092621,-0.019656887,0.023674952,-0.024975257,0.011931191,0.044140138,0.009295435,0.055058025,-0.018333152,0.0382829,0.017501423,0.03476856,-2.2296395e-5,-0.0050255093,0.051543683,0.004466143,-0.008481279,-0.017173419,-0.012686775,0.04025093,0.042570397,-0.030832494,0.021203198,0.049903657,0.0037105596,0.03762689,-0.04118809,-0.024740968,-0.03608058,0.016892271,-0.02490497,-0.019258594,0.037509743,-0.063117586,0.010994034,-0.05927