INSERT INTO `messages` VALUES (2,5,'incoming','text','What are your prices?',NULL,0,1,NULL,'2026-02-28 20:58:51','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(3,5,'outgoing','text','Our team will respond shortly.',NULL,0,0,NULL,'2026-02-28 20:58:51','2026-02-28 20:58:51',NULL,NULL,NULL,NULL),(4,5,'incoming','text','Hello',NULL,0,1,NULL,'2026-02-28 21:00:29','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(5,5,'outgoing','text','Our team will respond shortly.',NULL,0,0,NULL,'2026-02-28 21:00:29','2026-02-28 21:00:29',NULL,NULL,NULL,NULL),(6,5,'incoming','text','What are your prices?',NULL,0,1,NULL,'2026-02-28 21:02:54','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(7,5,'outgoing','text','Our pricing starts at $29 per month.',NULL,0,0,NULL,'2026-02-28 21:02:55','2026-02-28 21:02:55',NULL,NULL,NULL,NULL),(8,5,'incoming','text','Hello',NULL,0,1,NULL,'2026-02-28 21:03:12','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(9,5,'outgoing','text','Hello! How can I assist you today?',NULL,0,0,NULL,'2026-02-28 21:03:14','2026-02-28 21:03:14',NULL,NULL,NULL,NULL),(10,5,'incoming','text','I need to study in USA',NULL,0,1,NULL,'2026-02-28 21:03:34','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(11,5,'outgoing','text','I can assist with general inquiries about studying in the USA. If you need information on universities, visa requirements, or application processes, please let me know how I can help!',NULL,0,0,NULL,'2026-02-28 21:03:36','2026-02-28 21:03:36',NULL,NULL,NULL,NULL),(12,5,'incoming','text','Which programs ?',NULL,0,1,NULL,'2026-02-28 21:04:29','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(13,5,'outgoing','text','Could you please provide more context or specify which programs you are referring to? This will help me assist you better.',NULL,0,0,NULL,'2026-02-28 21:04:30','2026-02-28 21:04:30',NULL,NULL,NULL,NULL),(14,5,'incoming','text','Price',NULL,0,1,NULL,'2026-02-28 21:04:53','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(15,5,'outgoing','text','Our pricing starts at $29 per month.',NULL,0,0,NULL,'2026-02-28 21:04:53','2026-02-28 21:04:53',NULL,NULL,NULL,NULL),(16,5,'incoming','text','Need computer science',NULL,0,1,NULL,'2026-02-28 21:07:05','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(17,5,'outgoing','text','Could you please provide more details about what you need related to computer science? Are you looking for resources, support, or something else?',NULL,0,0,NULL,'2026-02-28 21:07:05','2026-02-28 21:07:05',NULL,NULL,NULL,NULL),(18,5,'incoming','text','Official website',NULL,0,1,NULL,'2026-02-28 21:38:22','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(19,5,'outgoing','text','www.visaconsultantcanada.com and www.visaconsultantcanada.ca.',NULL,0,0,NULL,'2026-02-28 21:38:22','2026-02-28 21:38:22',NULL,NULL,NULL,NULL),(20,5,'incoming','text','What are your address ?',NULL,0,1,NULL,'2026-02-28 21:38:57','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(21,5,'outgoing','text','Our company is located in Gasanze Cell, Nduba Sector, Gasabo District, Kigali, Republic of Rwanda.',NULL,0,0,NULL,'2026-02-28 21:38:58','2026-02-28 21:38:58',NULL,NULL,NULL,NULL),(22,5,'incoming','text','Head office plz',NULL,0,1,NULL,'2026-02-28 21:39:21','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(23,5,'outgoing','text','Our head office is located in Gasanze Cell, Nduba Sector, Gasabo District, Kigali, Republic of Rwanda. If you need further assistance or wish to visit, please contact us to schedule an appointment.',NULL,0,0,NULL,'2026-02-28 21:39:22','2026-02-28 21:39:22',NULL,NULL,NULL,NULL),(24,5,'incoming','text','How about musanze',NULL,0,1,NULL,'2026-02-28 21:39:55','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(25,5,'outgoing','text','Could you please clarify your question about Musanze? Are you asking if Parrot Canada Visa Consultant Company Ltd. has an office there, or are you inquiring about services related to that location?',NULL,0,0,NULL,'2026-02-28 21:39:56','2026-02-28 21:39:56',NULL,NULL,NULL,NULL),(26,5,'incoming','text','Which services are you providing ?',NULL,0,1,NULL,'2026-02-28 21:40:58','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(27,5,'outgoing','text','Parrot Canada Visa Consultant Company Ltd. provides the following services:\n\n1. **Student Visa Assistance**: We assist students applying for visas to study in Canada, USA, Europe, South Korea, and selected Asian countries.\n\n2. **University Admission Support**: We help students with the application process for universities and educational institutions in the aforementioned countries.\n\n3. **Short Course Assistance**: We support students enrolling in Spring, Summer, Fall, and Winter short courses worldwide.\n\n4. **Consultation with Immigration Lawyers**: We work with immigration lawyers, particularly for Canadian immigration services, to provide expert guidance.\n\nAll services are provided under a legally binding International Student Admission and Visa Consultancy Agreement, ensuring confidentiality and professionalism.',NULL,0,0,NULL,'2026-02-28 21:41:01','2026-02-28 21:41:01',NULL,NULL,NULL,NULL),(28,5,'incoming','text','And which pages do you have and their prices ?',NULL,0,1,NULL,'2026-02-28 21:41:50','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(29,5,'outgoing','text','Parrot Canada Visa Consultant Company Ltd. does not provide specific information about pages or prices in the provided company knowledge. For detailed information regarding services and pricing, please contact us directly via email at infos@visaconsultantcanada.com or visit our website at www.visaconsultantcanada.com.',NULL,0,0,NULL,'2026-02-28 21:41:51','2026-02-28 21:41:51',NULL,NULL,NULL,NULL),(30,5,'incoming','text','Study in Korea',NULL,0,1,NULL,'2026-02-28 21:42:23','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(31,5,'outgoing','text','Parrot Canada Visa Consultant Company Ltd. assists students who wish to study in South Korea. We provide guidance on the application process, including selecting suitable programs and institutions, preparing necessary documentation, and navigating the visa application process. However, please note that we do not guarantee university admission or visa approval, as these decisions are made by the respective educational institutions and immigration authorities. For further assistance, you can contact us via email at infos@visaconsultantcanada.com or visit our website at www.visaconsultantcanada.com.',NULL,0,0,NULL,'2026-02-28 21:42:24','2026-02-28 21:42:24',NULL,NULL,NULL,NULL),(34,5,'incoming','text','Hello',NULL,0,1,NULL,'2026-02-28 22:29:21','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(35,5,'outgoing','text','Hello! How can I assist you today with your visa-related inquiries?',NULL,0,0,NULL,'2026-02-28 22:29:24','2026-02-28 22:29:24',NULL,NULL,NULL,NULL),(36,5,'incoming','text','Company office is where ?',NULL,0,1,NULL,'2026-02-28 22:29:54','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(37,5,'outgoing','text','Yes. You may visit our Kigali office by appointment.',NULL,0,0,NULL,'2026-02-28 22:29:57','2026-02-28 22:29:57',NULL,NULL,NULL,NULL),(38,5,'incoming','text','When ?',NULL,0,1,NULL,'2026-02-28 22:30:21','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(39,5,'outgoing','text','Could you please provide more context or specify what you are asking about? This will help me assist you better.',NULL,0,0,NULL,'2026-02-28 22:30:22','2026-02-28 22:30:22',NULL,NULL,NULL,NULL),(40,5,'incoming','text','What is company name ?',NULL,0,1,NULL,'2026-02-28 22:30:45','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(41,5,'outgoing','text','Our company is officially registered as Parrot Canada Visa Consultant Company Ltd.',NULL,0,0,NULL,'2026-02-28 22:30:45','2026-02-28 22:30:45',NULL,NULL,NULL,NULL),(42,5,'incoming','text','Who is the managing Director ?',NULL,0,1,NULL,'2026-02-28 22:31:17','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(43,5,'outgoing','text','The Managing Director is Dr. TWAJAMAHORO Jean Pierre.',NULL,0,0,NULL,'2026-02-28 22:31:17','2026-02-28 22:31:17',NULL,NULL,NULL,NULL),(44,5,'incoming','text','Do you have other staffs ?',NULL,0,1,NULL,'2026-02-28 22:31:36','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(45,5,'outgoing','text','Service fees are non-refundable once services have commenced.',NULL,0,0,NULL,'2026-02-28 22:31:37','2026-02-28 22:31:37',NULL,NULL,NULL,NULL),(46,5,'incoming','text','Hello',NULL,0,1,NULL,'2026-02-28 22:40:52','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(47,5,'outgoing','text','Hello! How can I assist you today with your visa-related inquiries?',NULL,0,0,NULL,'2026-02-28 22:40:54','2026-02-28 22:40:54',NULL,NULL,NULL,NULL),(48,5,'incoming','text','I need to study in USA ?',NULL,0,1,NULL,'2026-02-28 22:41:15','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(49,5,'outgoing','text','To study in the USA, you will need to follow these steps:\n\n1. **Choose a Program and Institution**: Research and select the university or college that offers the program you are interested in.\n\n2. **Apply to the Institution**: Complete the application process for your chosen institution. This may include submitting transcripts, letters of recommendation, and standardized test scores (like TOEFL or IELTS for non-native English speakers).\n\n3. **Receive Acceptance**: Once accepted, you will receive an I-20 form, which is necessary for your visa application.\n\n4. **Pay the SEVIS Fee**: Before applying for your visa, you must pay the SEVIS (Student and Exchange Visitor Information System) fee.\n\n5. **Apply for a Student Visa**: You will need to apply for an F-1 visa (for academic studies) or M-1 visa (for vocational studies) at a U.S. embassy or consulate. This involves filling out the DS-160 form, paying the visa application fee, and scheduling an interview.\n\n6. **Prepare for the Visa Interview**: Gather necessary documents, including your passport, I-20 form, SEVIS fee receipt, financial evidence, and any other required documents.\n\n7. **Attend the Visa Interview**: Present your documents and answer questions regarding your study plans and intentions in the U.S.\n\n8. **Travel to the USA**: Once your visa is approved, you can make travel arrangements to the U.S. and prepare for your studies.\n\nIf you need assistance with any specific step or require more detailed information, please let me know!',NULL,0,0,NULL,'2026-02-28 22:41:22','2026-02-28 22:41:22',NULL,NULL,NULL,NULL),(50,5,'incoming','text','What is SEVIS ?',NULL,0,1,NULL,'2026-02-28 22:42:02','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(51,5,'outgoing','text','No. Government fees are paid separately by the student.',NULL,0,0,NULL,'2026-02-28 22:42:02','2026-02-28 22:42:02',NULL,NULL,NULL,NULL),(52,5,'incoming','text','Hello',NULL,0,1,NULL,'2026-02-28 22:53:04','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(53,5,'outgoing','text','Hello! How can I assist you today with your visa-related inquiries?',NULL,0,0,NULL,'2026-02-28 22:53:04','2026-02-28 22:53:04',NULL,NULL,NULL,NULL),(54,5,'incoming','text','What is SEVIS ?',NULL,0,1,NULL,'2026-02-28 22:53:26','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(55,5,'outgoing','text','No. Government fees are paid separately by the student.',NULL,0,0,NULL,'2026-02-28 22:53:26','2026-02-28 22:53:26',NULL,NULL,NULL,NULL),(56,5,'incoming','text','Need requirements for admissions',NULL,0,1,NULL,'2026-02-28 22:54:02','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(57,5,'outgoing','text','Please contact our team for accurate assistance.',NULL,0,0,NULL,'2026-02-28 22:54:04','2026-02-28 22:54:04',NULL,NULL,NULL,NULL),(58,5,'incoming','text','Need to study in USA ?',NULL,0,1,NULL,'2026-02-28 22:54:40','2026-03-02 14:50:05',NULL,NULL,NULL,NULL),(59,5,'outgoing','text','We offer USA study services, including both loan-based and self-sponsored options. The total USA loan-based package is USD 3,000, which includes admission support, mock interview training, loan processing assistance, and visa documentation preparation. The total service package without a loan is USD 2,300. Please contact our team for accurate assistance.',NULL,0,0,NULL,'2026-02-28 22:54:42','2026-02-28 22:54:42',NULL,NULL,NULL,NUL